            code += f"(var OR_VAR = {generate_random_boolean()}); // {logic_shard_type}\n"
        elif logic_shard_type == "NOT":
            code += f"(var NOT_VAR = !{generate_random_boolean()}); // {logic_shard_type}\n"
        elif logic_shard_type == "XOR":
            code += f"(var XOR_VAR = {generate_random_boolean()} ? {generate_random_boolean()} : {generate_random_boolean()}); // {logic_shard_type}\n"

    # CODE GENERATION PHASE 3: OPERATOR INTEGRATION
    operator_count = 10

    for _ in range(operator_count):
        variable = random.choice(list(variable_types.keys()))
        operator = generate_random_operator()
        constant = generate_random_number(0, 100)
        new_variable = generate_random_string(5)

        if operator == "+":
            code += f"{new_variable} = {variable} {operator} {constant}; // {operator}\n"
        elif operator == "-":
            code += f"{new_variable} = {variable} {operator} {constant}; // {operator}\n"
        elif operator == "*":
            code += f"{new_variable} = {variable} {operator} {constant}; // {operator}\n"
        elif operator == "/":
            code += f"{new_variable} = {variable} {operator} {constant}; // {operator}\n"
        elif operator == "%":
            code += f"{new_variable} = {variable} {operator} {constant}; // {operator}\n"
        elif operator == "==":
            code += f"{new_variable} = {variable} {operator} {constant}; // {operator}\n"
        elif operator == "!=":
            code += f"{new_variable} = {variable} {operator} {constant}; // {operator}\n"
        elif operator == ">=":
            code += f"{new_variable} = {variable} {operator} {constant}; // {operator}\n"
        elif operator == "<=":
            code += f"{new_variable} = {variable} {operator} {constant}; // {operator}\n"

    # CODE GENERATION PHASE 4: FINALIZATION
    code += f"\nvar FINAL_VARIABLE = {random.choice([True, False])} ? {generate_random_number(0, 100)} : {generate_random_number(0, 100)};"

    return code

